const jwt = require('jsonwebtoken');
const config = require('../config'); // Assumed to contain JWT_SECRET

const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1]; // Expected: Bearer TOKEN

  if (token == null) {
    // No token provided in the request
    console.warn('Authentication attempt: No token provided.');
    return res.status(401).json({ message: 'Authentication required: No token provided.' });
  }

  jwt.verify(token, config.jwtSecret, (err, user) => {
    if (err) {
      // Token is invalid or expired
      console.error('JWT verification failed:', err.message); // Log the specific error
      return res.status(403).json({ message: `Authentication failed: ${err.message}` });
    }
    req.user = user; // Attach user payload to request for subsequent handlers
    next(); // Proceed to the next middleware/route handler
  });
};

module.exports = authenticateToken;

