  const { isAuthenticated, getAuthToken } = useContext(AuthContext); // Use a method to get token
  const [holidayMessage, setHolidayMessage] = useState(null);
  const [error, setError] = useState(null);

  useEffect(() => {
    // Only attempt to fetch if the user is authenticated
    if (isAuthenticated) {
      const authToken = getAuthToken(); // Retrieve current token
      if (!authToken) {
        // Should not happen if isAuthenticated is true, but as a safeguard
        console.warn('Authenticated user without a token.');
        setError('Not authenticated.');
        return;
      }

      const fetchHolidayMessage = async () => {
        try {
          const response = await fetch('https://coaileague.com/api/mascot/holiday', {
            headers: {
              'Authorization': `Bearer ${authToken}`
            }
          });

          if (response.status === 401) {
            // The global auth interceptor/context should handle redirects on 401.
            // For this specific component, just clear the message.
            setError('Session expired or unauthorized.');
            setHolidayMessage(null);
            return;
          }

          if (!response.ok) {
            throw new Error(`HTTP error! status: ${response.status}`);
          }

          const data = await response.json();
          setHolidayMessage(data.message);
        } catch (err) {
          console.error("Failed to fetch mascot holiday message:", err);
          setError("Failed to load holiday message.");
        }
      };

      fetchHolidayMessage();
    } else {
      // Clear any previous state if the user becomes unauthenticated
      setHolidayMessage(null);
      setError(null);
    }
  }, [isAuthenticated, getAuthToken]); // Re-run effect when authentication state changes

  // Do not render anything related to this feature if not authenticated
  if (!isAuthenticated) return null;

  if (error) return <div className="error">Error: {error}</div>;
  if (!holidayMessage) return <div>Loading mascot holiday message...</div>;

  return (
    <div className="mascot-holiday-widget">
      <h3>Your CoAIleague Mascot says:</h3>
      <p>{holidayMessage}</p>
    </div>
  );
};

